function fibonacci(n: number): number {
  if (n <= 1) return n;
  return fibonacci(n - 1) + fibonacci(n - 2);
}

function memoize<T extends (arg: any) => any>(fn: T): T {
  const cache = new Map<any, ReturnType<T>>();
  return ((arg: any) => {
    if (cache.has(arg)) {
      return cache.get(arg)!;
    }
    const result = fn(arg);
    cache.set(arg, result);
    return result;
  }) as T;
}

function memoizeMultiArgs<T extends (...args: any[]) => any>(fn: T): T {
  const cache = new Map<string, ReturnType<T>>();
  return ((...args: any[]) => {
    const key = JSON.stringify(args);
    if (cache.has(key)) {
      return cache.get(key)!;
    }
    const result = fn(...args);
    cache.set(key, result);
    return result;
  }) as T;
}

function memoizeObjectArgs<T extends (...args: any[]) => any>(fn: T): T {
  const rootCache = new WeakMap<object, any>();
  return function memoized(...args: any[]): any {
    let currentCache = rootCache;

    for (let i = 0; i < args.length - 1; i++) {
      const arg = args[i];
      if (typeof arg !== 'object' || arg === null) {
        // fallback for primitive values, use Map instead or serialize
        throw new Error('memoizeObjectArgs supports only object arguments');
      }
      if (!currentCache.has(arg)) {
        currentCache.set(arg, new WeakMap());
      }
      currentCache = currentCache.get(arg);
    }

    // Last argument cache
    const lastArg = args[args.length - 1];
    if (currentCache.has(lastArg)) {
      return currentCache.get(lastArg);
    }

    const result = fn(...args);
    currentCache.set(lastArg, result);
    return result;
  } as T;
}

type User = {
  id: number;
  name: string;
};

type CustomError = {
  message: string;
  code: number;
};

function fetchUser(id: number): User | CustomError {
  if (id === 1) {
    return { id: 1, name: "Alice" };
  } else {
    return { message: "User not found", code: 404 };
  }
}

type FetchUserReturn = ReturnType<typeof fetchUser>;

// To get the success type (User) only:
type Success = Exclude<FetchUserReturn, CustomError>;

// To get the error type only:
type Failure = Extract<FetchUserReturn, CustomError>;

// Usage example
function handleResult(result: FetchUserReturn) {
  if ("message" in result) {
    // result is inferred as CustomError
    console.error(`Error: ${result.message} (code: ${result.code})`);
  } else {
    // result is inferred as User
    console.log(`User fetched: ${result.name}`);
  }
}

type ErrorDetails = {
  message: string;
  code: number;
  stack?: string;
};

// Sometimes you might receive only part of the error information
const partialError: Partial<ErrorDetails> = {
  message: "Something went wrong"
};

function logCompleteError(error: Required<ErrorDetails>) {
  console.error(`Error: ${error.message}, Code: ${error.code}, Stack: ${error.stack}`);
}

const errorMessages: Record<number, string> = {
  404: "Not Found",
  500: "Internal Server Error",
  401: "Unauthorized"
};

function getErrorMessage(code: number): string {
  return errorMessages[code] || "Unknown error";
}

class MyMeta(type):
    def __new__(cls, name, bases, dct):
        print(f"Creating class {name}")
        return super().__new__(cls, name, bases, dct)

class MyClass(metaclass=MyMeta):
    pass

# When you run this, it prints:
# Creating class MyClass

class VerboseMeta(type):
    def __new__(cls, name, bases, dct):
        print(f"__new__ for {name}")
        return super().__new__(cls, name, bases, dct)

    def __init__(cls, name, bases, dct):
        print(f"__init__ for {name}")
        super().__init__(name, bases, dct)

class Demo(metaclass=VerboseMeta):
    pass

# Output:
# __new__ for Demo
# __init__ for Demo

def hello_method(self):
    print(f"Hello from {self.__class__.__name__}!")

class AutoHelloMeta(type):
    def __new__(cls, name, bases, dct):
        if 'hello' not in dct:
            dct['hello'] = hello_method
        return super().__new__(cls, name, bases, dct)

class Person(metaclass=AutoHelloMeta):
    pass

p = Person()
p.hello()  # Output: Hello from Person!

def divide(x, y):
    try:
        result = x / y
    except ZeroDivisionError as e:
        # Raise a new exception but keep original context
        raise ValueError('Invalid inputs for division') from e
    return result

try:
    divide(10, 0)
except ValueError as err:
    print('Caught an error:', err)
    # The original ZeroDivisionError is still shown in the traceback
